const now = new Date();
const tomorrow = new Date(now);
tomorrow.setDate(now.getDate() + 1);

const pad = (n) => String(n).padStart(2, '0');
const year = tomorrow.getFullYear();
const month = pad(tomorrow.getMonth() + 1);
const day = pad(tomorrow.getDate());

const start = `${year}-${month}-${day}T00:00:00-03:00`;
const end   = `${year}-${month}-${day}T23:59:59-03:00`;
const dateStr = `${day}/${month}/${year}`;

return [{ json: { start, end, tomorrow_date: dateStr } }];

const events = $input.all();
const results = [];

for (const item of events) {
  const ev = item.json;
  const title = ev.summary || '';
  const desc = ev.description || '';

  // Só eventos Nutriskin
  if (!title.toLowerCase().includes('nutriskin')) continue;

  // Extrai telefone da descrição
  const telMatch = desc.match(/Telefone:\s*(\S+)/);
  if (!telMatch) continue;

  let telefone = telMatch[1].trim().replace('@s.whatsapp.net', '');

  // Extrai nome
  const nomeMatch = desc.match(/Paciente:\s*(.+)/);
  const nome = nomeMatch ? nomeMatch[1].trim() : title.replace(/Nutriskin\s*[—-]\s*/,'').replace(/\s*\(.*\)$/,'').trim();

  // Extrai tipo da descrição
  const tipoMatch = desc.match(/Tipo:\s*(.+)/);
  const tipoRaw = tipoMatch ? tipoMatch[1].trim().toLowerCase() : '';

  // Classifica tipo_consulta
  let tipo_consulta = 'reconsulta_presencial';
  const isOnline = tipoRaw.includes('online') || title.toLowerCase().includes('online');
  const isPrimeira = tipoRaw.includes('1ª') || tipoRaw.includes('primeira') || tipoRaw.includes('1a');

  if (isPrimeira && isOnline) tipo_consulta = '1a_consulta_online';
  else if (isPrimeira && !isOnline) tipo_consulta = '1a_consulta_presencial';
  else if (!isPrimeira && isOnline) tipo_consulta = 'reconsulta_online';
  else tipo_consulta = 'reconsulta_presencial';

  // Formata horário
  const startTime = ev.start?.dateTime || ev.start?.date || '';
  const startDate = new Date(startTime);
  const hora = startDate.getHours();
  const min = startDate.getMinutes();
  const horarioFormatado = min === 0 ? `${hora}h` : `${hora}h${String(min).padStart(2,'0')}min`;

  const diasSemana = ['domingo','segunda-feira','terça-feira','quarta-feira','quinta-feira','sexta-feira','sábado'];
  const diaSemana = diasSemana[startDate.getDay()];

  const dia = String(startDate.getDate()).padStart(2,'0');
  const mes = String(startDate.getMonth()+1).padStart(2,'0');
  const dataFormatada = `${dia}/${mes}`;

  results.push({
    json: { telefone, nome, horario: horarioFormatado, dia_semana: diaSemana, data: dataFormatada, tipo_consulta, event_id: ev.id }
  });
}

if (results.length === 0) {
  return [{ json: { skip: true } }];
}

return results;

// Monta mensagem de confirmação 48h conforme tipo
const { nome, horario, dia_semana, data, tipo_consulta, modalidade } = $json;

let mensagem = '';

const base = `Olá, ${nome}. Tudo bem? Passando para confirmar a sua consulta `;

switch (tipo_consulta) {
  case '1a_consulta_presencial':
    mensagem = `${base}amanhã, ${dia_semana}, dia ${data}, às ${horario}, no consultório (presencial). Você consegue comparecer?\n\nLembrando: caso ainda não tenha preenchido o formulário pré-consulta, segue o link: [LINK_FORMULARIO_PRE_CONSULTA]\n\nAguardamos você!`;
    break;

  case '1a_consulta_online':
    mensagem = `${base}online amanhã, ${dia_semana}, dia ${data}, às ${horario}. Você consegue comparecer?\n\nLembrando: caso ainda não tenha preenchido o formulário pré-consulta, segue o link: [LINK_FORMULARIO_PRE_CONSULTA]\n\nLembrando também de enviar as fotos conforme as orientações, caso ainda não tenha enviado.\n\nSegue novamente o link da sessão online: [LINK_VIDEOCHAMADA]\n\nAguardamos você!`;
    break;

  case 'reconsulta_presencial':
    mensagem = `${base}amanhã, ${dia_semana}, dia ${data}, às ${horario}, no consultório (presencial). Você consegue comparecer?\n\nAguardamos você!`;
    break;

  case 'reconsulta_online':
    mensagem = `${base}online amanhã, ${dia_semana}, dia ${data}, às ${horario}. Você consegue comparecer?\n\nLembrando de enviar as fotos conforme as orientações, caso ainda não tenha enviado.\n\nSegue novamente o link da sessão online: [LINK_VIDEOCHAMADA]\n\nAguardamos você!`;
    break;

  default:
    mensagem = `${base}amanhã, ${dia_semana}, dia ${data}, às ${horario}. Você consegue comparecer?\n\nAguardamos você!`;
}

return [{
  json: {
    ...$json,
    mensagem
  }
}];

// Corrige telefone para formato Evolution API
let telefone = $json.telefone;

// Remove caracteres não numéricos
telefone = telefone.replace(/\D/g, '');

// Garante código do país 55
if (!telefone.startsWith('55')) {
  telefone = '55' + telefone;
}

// Correção do nono dígito para celulares brasileiros (DDD + 8 dígitos)
// Formato esperado: 55 + DDD(2) + número(9)
if (telefone.length === 12) {
  // Faltando o 9: 55 + DDD(2) + 8 dígitos → inserir 9 após DDD
  telefone = telefone.slice(0, 4) + '9' + telefone.slice(4);
}

return [{
  json: {
    ...$json,
    telefone_formatado: telefone
  }
}];
